from matplotlib import pyplot as pltimport numpy as npfrom skimage import io, img_as_floatfrom skimage.filters import gaussianimport cv2img = io.imread("../data/BSE_25sigma_noisy.jpg", as_gray = True)kernel = np.ones((5,5),np.float32)/25gaussian_kernel = np.array([[1/16,1/8,1/16],                           [1/8,1/4,1/8],                           [1/16,1/8,1/16]                           ])conv_using_cv2 = cv2.filter2D(img, -1, gaussian_kernel, borderType = cv2.BORDER_CONSTANT)#border = padding#-1 means the same data type as input imggaussian_using_skimage = gaussian(img, sigma =1, mode = 'constant', cval = 0.0)#cval = constant value (padding)plt.figure()plt.subplot(1,2,1)plt.imshow(img)plt.title("Original Image")plt.subplot(1,2,2)plt.imshow(conv_using_cv2)plt.title("After")